(function (root, factory) {
  const api = factory();
  if (typeof module === "object" && module.exports) module.exports = api;
  if (root) root.SoftoraPremiumDatabaseTargetCoords = api;
})(typeof window !== "undefined" ? window : globalThis, function () {
  "use strict";

  // Generated from PDOK Locatieserver woonplaats centroids (2026-05-21).
  const DATA_BASE64 = [
    "",
    "",
    "",
    "",
    "",
    "",
    "",
    "",
    "",
    "",
    "",
    "",
    "",
    "",
    ""
  ].join("");
  let cache = null;

  function decodeBase64(value) {
    if (typeof Buffer !== "undefined") return Buffer.from(value, "base64").toString("utf8");
    return atob(value);
  }

  function normalizeText(value) {
    return String(value || "")
      .toLowerCase()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "")
      .replace(/['\u2019]/g, "")
      .replace(/\((?:n\.?\s*br|nb|noord\s*brabant|nh\.?|noord\s*holland|l\.?|limburg)\)/g, " ")
      .replace(/\bfriesland\b/g, "fryslan")
      .replace(/\s+(?:dr|fr|gn|gr|l|nb|nh)\s*$/g, "")
      .replace(/\b(?:gem|gemeente)\b/g, " ")
      .replace(/\s+ac$/g, "")
      .replace(/[^a-z0-9]+/g, " ")
      .trim();
  }

  function addUnique(map, key, coords) {
    if (!key) return;
    if (Object.prototype.hasOwnProperty.call(map, key)) {
      map[key] = null;
      return;
    }
    map[key] = coords;
  }

  function getCache() {
    if (cache) return cache;
    const exact = Object.create(null);
    const byProvincePlace = Object.create(null);
    const byPlace = Object.create(null);
    const placeEntries = [];
    decodeBase64(DATA_BASE64).split("\n").forEach(function (line) {
      const parts = line.split("|");
      if (parts.length !== 5) return;
      const coords = { lat: Number(parts[3]), lng: Number(parts[4]) };
      if (!Number.isFinite(coords.lat) || !Number.isFinite(coords.lng)) return;
      const province = normalizeText(parts[0]);
      const municipality = normalizeText(parts[1]);
      const place = normalizeText(parts[2]);
      exact[province + "|" + municipality + "|" + place] = coords;
      addUnique(byProvincePlace, province + "|" + place, coords);
      addUnique(byPlace, place, coords);
      placeEntries.push({
        province: province,
        municipality: municipality,
        place: place,
        coords: coords,
        provincePattern: buildNormalizedPhrasePattern(province),
        municipalityPattern: buildNormalizedPhrasePattern(municipality),
        placePattern: buildNormalizedPhrasePattern(place)
      });
    });
    placeEntries.sort(function (left, right) {
      return right.place.length - left.place.length;
    });
    cache = { exact: exact, byProvincePlace: byProvincePlace, byPlace: byPlace, placeEntries: placeEntries };
    return cache;
  }

  function escapeRegExp(value) {
    return String(value || "").replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  }

  function buildNormalizedPhrasePattern(value) {
    const phrase = normalizeText(value);
    if (!phrase) return null;
    return new RegExp("(^|\\s)" + escapeRegExp(phrase).replace(/\s+/g, "\\s+") + "(\\s|$)");
  }

  function matchesNormalizedPhrase(normalizedText, pattern) {
    return Boolean(normalizedText && pattern && pattern.test(normalizedText));
  }

  function hasNormalizedPhrase(text, phrase) {
    const normalizedText = normalizeText(text);
    return matchesNormalizedPhrase(normalizedText, buildNormalizedPhrasePattern(phrase));
  }

  function getTargetCoords(target) {
    const parts = target && typeof target === "object" ? target : {};
    const province = normalizeText(parts.province);
    const municipality = normalizeText(parts.municipality);
    const place = normalizeText(parts.place);
    if (!place) return null;
    const maps = getCache();
    return maps.exact[province + "|" + municipality + "|" + place] ||
      maps.byProvincePlace[province + "|" + place] ||
      maps.byPlace[place] ||
      null;
  }

  function resolveTextCoords(value, hints) {
    const text = normalizeText(value);
    if (!text) return null;
    const maps = getCache();
    const province = normalizeText(hints && hints.province);
    const municipality = normalizeText(hints && hints.municipality);

    for (let index = 0; index < maps.placeEntries.length; index += 1) {
      const entry = maps.placeEntries[index];
      if (!matchesNormalizedPhrase(text, entry.placePattern)) continue;
      if (province && entry.province !== province) continue;
      if (municipality && entry.municipality !== municipality) continue;
      if (province || municipality) return entry.coords;
    }

    for (let index = 0; index < maps.placeEntries.length; index += 1) {
      const entry = maps.placeEntries[index];
      if (!matchesNormalizedPhrase(text, entry.placePattern)) continue;
      if (matchesNormalizedPhrase(text, entry.provincePattern) || matchesNormalizedPhrase(text, entry.municipalityPattern)) {
        return entry.coords;
      }
    }

    for (let index = 0; index < maps.placeEntries.length; index += 1) {
      const entry = maps.placeEntries[index];
      if (!matchesNormalizedPhrase(text, entry.placePattern)) continue;
      const uniqueCoords = maps.byPlace[entry.place];
      if (uniqueCoords) return uniqueCoords;
    }

    return null;
  }

  return Object.freeze({
    getTargetCoords: getTargetCoords,
    hasNormalizedPhrase: hasNormalizedPhrase,
    normalizeText: normalizeText,
    resolveTextCoords: resolveTextCoords
  });
});
